fn solve(nums1: Array(Int64)) -> Bool {
	let n = nums1.len
	if n <= 1 {
		return true
	}

	var odd_numbers: Array(Int64) = []
	var even_numbers: Array(Int64) = []

	for num in nums1 {
		// Since nums1[i] >= 1, we don't worry about 0 parity issues with standard % 2
		if num % 2 != 0 {
			odd_numbers.push(num)
		} else {
			even_numbers.push(num)
		}
	}

	let has_odd = odd_numbers.len > 0
	let has_even = even_numbers.len > 0

	// Case 1: All numbers are even (has_odd = false). Case E works.
	if !has_odd {
		return true
	}

	// Case 2: All numbers are odd (has_even = false). Case O works.
	if !has_even {
		return true
	}

	// Case 3: Mixed parity (has_odd && has_even). Case E is impossible. Check Case O.

	// Case O requires every even number E to be greater than O_min.
	// Find O_min
	let o_min = odd_numbers.min!

	// Check condition for Case O
	for e in even_numbers {
		if e <= o_min {
			// Cannot convert this even number e to odd parity
			return false
		}
	}

	// If all even numbers can be converted to odd parity, Case O holds.
	return true
}
